    .map(new MapFunction<OrderEvent, OrderEvent>() {
        @Override
        public OrderEvent map(OrderEvent value) throws Exception {
            // Your processing logic here
            return value;
        }
    });

// Define the schema for serialization
DataFormatSchema<OrderEvent> outputSchema = new AvroSerializationSchema<>(new SchemaRegistryClient("http://localhost:8081"), "processed-orders-value");

FlinkKafkaProducer<OrderEvent> kafkaSink = new FlinkKafkaProducer<>(
    "processed-orders",
    outputSchema,
    properties
);

