### 6. Register Schema Before Sending Messages

Ensure that the schema is registered with the Schema Registry before sending messages.

```java
import io.confluent.kafka.serializers.KafkaAvroSerializerConfig;
import org.apache.avro.Schema;
import org.apache.http.HttpResponse;
import org.apache.http.client.methods.HttpPost;
import org.apache.http.entity.StringEntity;
import org.apache.http.impl.client.CloseableHttpClient;
import org.apache.http.impl.client.HttpClients;

@Service
public class SchemaRegistryClient {

    private static final String SCHEMA_REGISTRY_URL = "http://localhost:8081";

    public void registerSchema(String subject, Schema schema) throws Exception {
        try (CloseableHttpClient httpClient = HttpClients.createDefault()) {
            HttpPost postRequest = new HttpPost(SCHEMA_REGISTRY_URL + "/subjects/" + subject + "/versions");

            String jsonSchema = schema.toString(true); // Pretty print the schema
            postRequest.setEntity(new StringEntity(jsonSchema));
            postRequest.setHeader("Content-Type", "application/vnd.schemaregistry.v1+json");

            HttpResponse response = httpClient.execute(postRequest);
            if (response.getStatusLine().getStatusCode() != 200) {
                throw new RuntimeException("Failed to register schema: " + response.getStatusLine());
            }
        }
    }
}
```

