       saga_id VARCHAR(255) NOT NULL,
       step VARCHAR(255) NOT NULL,
       status VARCHAR(255) NOT NULL,  -- e.g., "PENDING", "SUCCESS", "FAILED"
       timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP
   );
