import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaProducer;
import org.apache.flink.streaming.api.CheckpointingMode;

public class FlinkJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.get_execution_environment();

        // Enable checkpointing with exactly-once semantics
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set the restart strategy to fixed delay with 3 retries and a delay of 10 seconds between retries
        env.setRestartStrategy(RestartStrategies.fixedDelayRestart(
            3, // Number of restart attempts
            Time.seconds(10) // Delay between restarts in seconds
        ));

        Properties kafkaProps = new Properties();
        kafkaProps.setProperty("bootstrap.servers", "localhost:9092");

        FlinkKafkaConsumer<String> kafkaConsumer = new FlinkKafkaConsumer<>(
            "input_topic",
            new SimpleStringSchema(),
            kafkaProps
        );

        // Kafka producer configuration
        Properties producerProps = new Properties();
        producerProps.setProperty("bootstrap.servers", "localhost:9092");

        FlinkKafkaProducer<String> kafkaProducer = new FlinkKafkaProducer<>(
            "output_topic",
            new SimpleStringSchema(),
            producerProps,
            FlinkKafkaProducer.Semantic.EXACTLY_ONCE
        );

        // Register Avro schemas with the schema registry before starting the job
        SchemaRegistryClient schemaRegistryClient = new CachedSchemaRegistryClient("http://localhost:8081", 10);

        String subject = "input_topic-value";
        Schema avroSchema = new Schema.Parser().parse(new File("your_record.avsc"));

        // Register the Avro schema with BACKWARD_TRANSITIVE compatibility mode
        registerSchemaWithCompatibility(schemaRegistryClient, subject, avroSchema);

        // Your Flink job logic here

        env.addSource(kafkaConsumer)
           .map(new MyMapFunction())
           .addSink(kafkaProducer);

        env.execute("Flink Job with Checkpointing and Restart Strategy");
    }

    private static class MyMapFunction implements MapFunction<String, String> {
        @Override
        public String map(String value) throws Exception {
            // Your mapping logic here
            return "Processed: " + value;
        }
    }

    public static void registerSchemaWithCompatibility(SchemaRegistryClient schemaRegistryClient, String subject, Schema avroSchema) throws Exception {
        CompatibilityModeRequest compatibilityMode = new CompatibilityModeRequest(CompatibilityMode.BACKWARD_TRANSITIVE);
        schemaRegistryClient.updateCompatibility(subject, compatibilityMode);

        int id = schemaRegistryClient.register(subject, avroSchema);
        System.out.println("Registered schema ID: " + id);
    }
}
```

### Explanation

1. **Checkpointing & Restart Strategy**: Configure checkpointing with exactly-once semantics and a fixed delay restart strategy.
2. **Kafka Consumer/Producer Configuration**: Ensure Kafka producers and consumers use the correct Avro serializers/deserializers that are registered in the schema registry.
3. **Schema Registration**: Before starting the Flink job, register your Avro schemas with the schema registry using `BACKWARD_TRANSITIVE` compatibility mode.

### Ensuring Exactly-Once Semantics

By ensuring exactly-once semantics for both Kafka producers and consumers, you guarantee that each message is processed only once, even in the presence of retries or failures. This aligns well with our requirement to handle out-of-order events and late data effectively using event time and watermarks.

### Conclusion

Integrating schema registry compatibility requirements into your Flink jobs ensures backward compatibility across all versions of Avro schemas while maintaining robustness and reliability in your stream processing pipeline. This setup, combined with exactly-once semantics for Kafka producers/consumers, provides a solid foundation for handling transient failures and ensuring data consistency.

